const ExcelJS = require('exceljs');
return await (async () => {
  const data = $input.first().json;
  if (!data.hasBilling) return [{ json: { hasBilling: false } }];

  const normalize = (name) =>
    (name || '').replace(/株式会社|有限会社|合同会社|一般社団法人|一般財団法人/g, '').trim();

  const wb = new ExcelJS.Workbook();
  const downloadUrl = data['@microsoft.graph.downloadUrl'];

  if (downloadUrl) {
    try {
      const res = await this.helpers.httpRequest({
        method: 'GET', url: downloadUrl,
        encoding: 'arraybuffer', returnFullResponse: false
      });
      await wb.xlsx.load(Buffer.from(res), { useSharedStrings: false });
    } catch(e) {}
  }

  for (const site of data.billingSites) {
    const sheetName = normalize(site.companyName);
    let sheet = wb.getWorksheet(sheetName);
    if (!sheet) {
      sheet = wb.addWorksheet(sheetName);
      const hdr = sheet.getRow(1);
      hdr.getCell(1).value = '日付';
      hdr.getCell(2).value = '区分';
      hdr.getCell(3).value = '現場名';
      hdr.getCell(4).value = '人員名';
      hdr.getCell(5).value = '高速(円)';
      hdr.getCell(6).value = '距離(km)';
      hdr.getCell(7).value = '駐車場(円)';
      hdr.font = { bold: true };
      hdr.commit();
    }
    let lastRow = 1;
    sheet.eachRow((row, num) => { lastRow = num; });
    const newRow = sheet.getRow(lastRow + 1);
    newRow.getCell(1).value = data.parsedDate;
    newRow.getCell(2).value = site.kubun || '';
    newRow.getCell(3).value = site.propertyName || '';
    newRow.getCell(4).value = data.employeeName || '';
    newRow.getCell(5).value = site.highwayFee || 0;
    newRow.getCell(6).value = site.distance || 0;
    newRow.getCell(7).value = site.parkingFee || 0;
    newRow.commit();
    sheet.columns.forEach(col => {
      let maxLen = 4;
      col.eachCell({ includeEmpty: false }, cell => {
        const len = cell.value ? String(cell.value).length * 2 : 0;
        if (len > maxLen) maxLen = len;
      });
      col.width = Math.min(maxLen + 2, 30);
    });
  }

  const buf = await wb.xlsx.writeBuffer({ useSharedStrings: false });
  const bin = await this.helpers.prepareBinaryData(
    Buffer.from(buf), data.billingFileName,
    'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
  );
  return [{ json: { ...data }, binary: { data: bin } }];
})();

const data = $input.first().json;

const normalize = (name) =>
  (name || '').replace(/株式会社|有限会社|合同会社|一般社団法人|一般財団法人/g, '').trim();

const BILLING_COMPANIES = [
  '港振興業', 'トラストテクノス', '平成システム', 'FGE',
  'mtr', 'オークコミュニケーション', 'ライズ',
  '千里スカイハイツ管理組合', '菊次', 'ページ', 'G-STYLE', '梶原通信'
];

const parts = (data.parsedDate || '').split('/');
const year = parseInt(parts[0]) || 0;
const month = parseInt(parts[1]) || 0;
const billingFileName = `請求集計_${year}年${String(month).padStart(2,'0')}月.xlsx`;

const billingSites = (data.sites || []).filter(site => {
  const normalized = normalize(site.companyName);
  return BILLING_COMPANIES.some(c => normalized.includes(c) || c.includes(normalized));
});

return [{ json: { ...data, year, month, billingFileName, billingSites, hasBilling: billingSites.length > 0 }}];

